1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(liveCells: Cell[]): Cell[] {
15	  const aliveKeys = new Set(liveCells.map(cellKey));
16	  const isAlive = (cell: Cell): boolean => aliveKeys.has(cellKey(cell));
17	  const liveNeighborCount = (cell: Cell): number =>
18	    neighborsOf(cell).filter(isAlive).length;
19	
20	  const survivors = liveCells.filter((cell) => {
21	    const n = liveNeighborCount(cell);
22	    return n === 2 || n === 3;
23	  });
24	
25	  const birthCandidates = new Map<string, Cell>();
26	  for (const cell of liveCells.flatMap(neighborsOf)) {
27	    if (!isAlive(cell)) birthCandidates.set(cellKey(cell), cell);
28	  }
29	  const births = [...birthCandidates.values()].filter(
30	    (cell) => liveNeighborCount(cell) === 3,
31	  );
32	
33	  return [...survivors, ...births];
34	}
