4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with exactly 2 neighbors survives (survival) — center of row of 3 stays alive", () => {
15	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
16	    expect(result).toContainEqual([0, 1]);
17	  });
18	  it("live cell with 3 neighbors survives (survival) — block corner survives", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
20	    expect(result).toContainEqual([0, 0]);
21	  });
22	  it("live cell with 4 neighbors dies (overpopulation) — center with 4 diagonal neighbors dies", () => {
23	    const result = nextGeneration([[0, 0], [2, 0], [1, 1], [0, 2], [2, 2]]);
24	    expect(result).not.toContainEqual([1, 1]);
25	  });
26	  it("dead cell with exactly 3 neighbors becomes alive (reproduction) — L-shape produces new cell at (1,1)", () => {
27	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
28	    expect(result).toContainEqual([1, 1]);
29	  });
30	  it("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
31	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
32	    const result = nextGeneration(block);
33	    expect(result).toHaveLength(4);
34	    for (const cell of block) expect(result).toContainEqual(cell);
